mapper.select:
SELECT a.id, a.name, a.category_id, c.code as category_code, c.name as category_name, a.breed_id, b.code as breed_code, b.name as breed_name, a.description, a.first_found_time, a.location, a.is_adopted, a.status, ai.image_url FROM animals a LEFT JOIN animal_images ai ON a.id = ai.animal_id LEFT JOIN category c ON a.category_id = c.category_id LEFT JOIN breed b ON a.breed_id = b.breed_id
AND a.name LIKE CONCAT('%', #{name}, '%')
AND a.category_id = #{categoryId}
AND a.breed_id = #{breedId}
AND a.is_adopted = #{isAdopted}
AND a.status = #{status}
ORDER BY a.id ASC

mapper.update:
update animals
name = #{name}, category_id = #{categoryId}, breed_id = #{breedId}, description = #{description}, first_found_time = #{firstFoundTime}, location = #{location}, is_adopted = #{isAdopted}, status = #{status},
WHERE id = #{id}
